/**
 * Parses a packet containing a big-endian count N followed by N 8-byte records.
 * 
 * @param buf Pointer to the input buffer.
 * @param len Length of the input buffer in bytes.
 * @return Pointer to the allocated array of records, or NULL on failure.
 */
uint64_t* parse_packet(const uint8_t *buf, size_t len) {
    // Check if buffer is at least large enough to contain the 4-byte count header
    if (buf == NULL || len < 4) {
        return NULL;
    }

    // Read 4-byte big-endian count N
    // We use manual shifting to ensure big-endian interpretation regardless of host endianness
    uint32_t n = ((uint32_t)buf[0] << 24) |
                  ((uint32_t)buf[1] << 16) |
                  ((uint32_t)buf[2] << 8)  |
                  ((uint32_t)buf[3]);

    // Check for integer overflow/underflow: 
    // Ensure n is not so large that it exceeds the remaining buffer length.
    // Each record is 8 bytes.
    // To prevent overflow during the multiplication (n * 8), we check against remaining size.
    size_t header_size = 4;
    if (n > 0 && (size_t)n > (len - header_size) / 8) {
        return NULL; // Buffer too small for N records
    }

    // Check if n is 0 (valid, but should return a non-null pointer or handle accordingly)
    if (n == 0) {
        uint64_t *empty_arr = NULL;
        return empty_arr;
    }

    // Allocate memory for N 8-byte records
    // Using calloc or malloc; if allocation fails, it returns NULL.
    uint64_t *records = (uint64_t *)malloc(n * sizeof(uint64_t));
    if (records == NULL) {
        return NULL;
    }

    // Copy records from buffer
    // Offset starts at 4 (after the header)
    for (uint32_t i = 0; i < n; ++i) {
        // Copy 8 bytes into the record
        // Note: This assumes the input records are in the same endianness as the target system.
        // If the input records are also big-endian, use manual shifting or bswap.
        memcpy(&records[i], buf + header_size + (i * 8), 8);
    }

    return records;
}
