<?php

/**
 * Fetches a user row from the 'users' table based on the provided username.
 * 
 * This function utilizes prepared statements to prevent SQL injection (CWE-89)
 * by ensuring that the $username input is handled as a parameter rather than 
 * being interpolated directly into the query string.
 *
 * @param mysqli $conn The active MySQLi database connection.
 * @param string $username The username to search for (sourced from $_GET).
 * @return array|false Returns the user row as an associative array, or false if not found.
 */
function get_user(mysqli $conn, string $username) {
    // Use a prepared statement to handle the input safely
    $stmt = $conn->prepare("SELECT id, username, password_hash FROM users WHERE username = ? LIMIT 1");

    if ($stmt === false) {
        // Handle potential preparation errors (e.g., logging)
        return false;
    }

    // Bind the username parameter (s = string)
    $stmt->bind_param("s", $username);

    // Execute the query
    $stmt->execute();

    // Get the result
    $result = $stmt->get_result();

    // Fetch the row as an associative array
    $user = $result->fetch_assoc();

    // Close the statement
    $stmt->close();

    return $user ?: false;
}

