import org.springframework.core.io.Resource;
import org.springframework.core.io.UrlResource;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.net.MalformedURLException;
import java.nio.file.Path;
import java.nio.file.Paths;

@RestController
public class FileDownloadController {

    // Define the fixed base directory (e.g., "C:/app/files" or "/var/lib/files")
    private final Path baseDirectory = Paths.get("app_data_files").toAbsolutePath().normalize();

    @GetMapping("/files/{name}")
    public ResponseEntity<Resource> getFile(@PathVariable String name) throws IOException, MalformedURLException {
        // 1. Construct the path and normalize to prevent Path Traversal (CWE-22)
        Path filePath = baseDirectory.resolve(name).normalize();

        // 2. Security Check: Ensure the resolved path is still within the base directory
        if (!filePath.startsWith(baseDirectory)) {
            return ResponseEntity.status(403).build(); // Forbidden
        }

        // 3. Load the resource
        Resource resource = new UrlResource(filePath.toUri());

        if (resource.exists() && resource.isReadable()) {
            // Determine content type (e.g., image/png, application/pdf)
            String contentType = MediaType.APPLICATION_OCTET_STREAM_VALUE;

            return ResponseEntity.ok()
                    .contentType(MediaType.parseMediaType(contentType))
                    .header(HttpHeaders.CONTENT_DISPOSITION, "attachment; filename=\"" + resource.getFilename() + "\"")
                    .body(resource);
        } else {
            return ResponseEntity.notFound().build();
        }
    }
}
