const express = require('express');
const app = express();
const html = require('html');

app.get('/hello', (req, res) => {
    const name = req.query.name;

    // Validate that name exists to avoid "Hello, undefined!"
    if (!name) {
        return res.send('Hello, Guest!');
    }

    // Use html.EscapeString to prevent Cross-Site Scripting (XSS) 
    // when injecting user-controlled input into HTML.
    // This prevents CWE-79.
    const safeName = html.EscapeString(name);

    res.send(`<h1>Hello, ${safeName}!</h1>`);
});

// Security best practice: Set X-Frame-Options to prevent clickjacking.
// This follows the guidance for the 'app' context.
app.use((req, res, next) => {
    res.set('X-Frame-Options', 'DENY');
    next();
});

const PORT = 3000;
app.listen(PORT, () => {
    console.log(`Server running on http://localhost:${PORT}`);
});
