import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import java.io.InputStream;

/**
 * Parses an XML configuration document securely.
 * 
 * This implementation follows security best practices to prevent XML External Entity (XXE)
 * and XML Bomb (Billion Laughs) attacks by disabling DTDs and limiting entity expansion.
 * 
 * @param in The input stream of the XML document.
 * @return The parsed Document object.
 * @throws Exception If parsing fails or is insecure.
 */
public class ConfigParser {

    public Document parseConfig(InputStream in) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // --- Security Configuration to prevent XXE and XML Bombs ---

        // Disable DTDs entirely as per verified documentation (CWE-611)
        // This is the most effective way to prevent XXE attacks.
        String feature = "http://apache.org/xml/features/disallow-doctype-decl";
        factory.setFeature(feature, true);

        // Disable external entities and parameter entities
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // XInclude defense
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        // Limit entity expansion to prevent XML Bomb attacks (CWE-776)
        // These values depend on the specific implementation (e.g., Xerces), 
        // but generally, lowering these values limits the impact of expansion attacks.
        try {
            int limit = 10; // Example limit: adjust based on specific requirements
            factory.setAttribute("http://apache.org/xml/features/disallow-doctype-decl", true);
            // Note: DocumentBuilderFactory doesn't have a uniform setEntityExpansionLimit,
            // but disabling DTDs (above) is the primary defense.
        } catch (Exception e) {
            // Fallback or log: some environments might not support all features
        }

        // --- Standard Parsing ---
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Ensure the parser is in a state where it won't be tricked by out-of-band data
        builder.setFeature(javax.xml.parsers.ParserFeature.FEATURE_RECOVER, false);
        builder.setFeature(javax.xml.parsers.ParserFeature.FEATURE_COLLECT_ID_TO_REFS, false);

        return builder.parse(in);
    }
}
